import * as React from 'react';
import {useEffect, useState} from 'react';
import Card from '@mui/material/Card';
import CardMedia from '@mui/material/CardMedia';
import Grid from '@mui/material/Grid2';
import Typography from '@mui/material/Typography';
import {styled} from '@mui/material/styles';
import {Box, CircularProgress, Container, Pagination} from "@mui/material";


const SyledCard = styled(Card)(({theme}) => ({
    display: 'flex',
    flexDirection: 'column',
    padding: 0,
    height: '100%',
    backgroundColor: (theme.vars || theme).palette.background.paper,
    '&:hover': {
        backgroundColor: 'transparent', cursor: 'pointer',
    },
    '&:focus-visible': {
        outline: '3px solid', outlineColor: 'hsla(210, 98%, 48%, 0.5)', outlineOffset: '2px',
    },
}));

export default function MainContent() {
    const [focusedCardIndex, setFocusedCardIndex] = React.useState(null);
    const [images, setImages] = useState([]); // State to store the list of images
    const [loading, setLoading] = useState(true); // State for loading indicator
    const [page, setPage] = useState(1); // State for pagination
    const imagesPerPage = 9; // Number of images per page
    const path = 'https://raw.githubusercontent.com/brunopCunha/brunopCunha/assets/images/'

    // Fetch images from the GitHub repository
    useEffect(() => {
        const fetchImages = async () => {
            const repoOwner = 'brunopCunha'; // Replace with your GitHub username
            const repoName = 'brunopCunha'; // Replace with your repository name
            const path = 'images'; // Path to the images folder in your repo

            const apiUrl = `https://api.github.com/repos/${repoOwner}/${repoName}/contents/${path}?ref=assets`;

            try {
                const response = await fetch(apiUrl);
                const data = await response.json();
                const imageFiles = data
                    .filter(file => /\.(jpg|jpeg|png|gif)$/i.test(file.name)) // Filter image files
                    .map(file => file.name); // Extract filenames
                setImages(imageFiles);
            } catch (error) {
                console.error('Error fetching images:', error);
            } finally {
                setLoading(false);
            }
        };

        fetchImages();
    }, []);

    // Handle pagination
    const handlePageChange = (event, value) => {
        setPage(value);
    };

    // Calculate visible images for the current page
    const startIndex = (page - 1) * imagesPerPage;
    const visibleImages = images.slice(startIndex, startIndex + imagesPerPage);

    // Total number of pages
    const totalPages = Math.ceil(images.length / imagesPerPage);

    const handleFocus = (index) => {
        setFocusedCardIndex(index);
    };

    const handleBlur = () => {
        setFocusedCardIndex(null);
    };

    return (
        <Container sx={{py: 4}}>
            <Typography variant="h4" component="h2" gutterBottom>
                Gallery
            </Typography>
            {loading ? (<Box sx={{display: 'flex', justifyContent: 'center', mt: 4}}>
                <CircularProgress/>
            </Box>) : (<>
                <Grid container spacing={2} columns={12}>
                    {visibleImages.map((image, index) => (<Grid item key={index} xs={12} sm={4} md={6}>
                        <SyledCard
                            variant="outlined"
                            onFocus={() => handleFocus(0)}
                            onBlur={handleBlur}
                            tabIndex={0}
                            className={focusedCardIndex === 0 ? 'Mui-focused' : ''}>
                            <CardMedia
                                component="img"
                                alt={`${image}`}
                                height="200"
                                image={`${path}/thumbnails/${image}`} // Use the image path from the GitHub folder
                                sx={{borderBottom: '1px solid', borderColor: 'divider', aspectRatio: '16 / 9'}}/>
                        </SyledCard>
                    </Grid>))}
                </Grid>
                <Pagination
                    count={totalPages} page={page} onChange={handlePageChange}
                    siblingCount={2} boundaryCount={1}
                    variant="outlined" color="secondary" shape="rounded"
                    sx={{mt: 4, display: 'flex', justifyContent: 'center'}}
                />
            </>)}
        </Container>
    );
}
